const _ = require('lodash');
const { Problem } = require('../models');

/**
 * Fetch problems with optional filters and include metadata with language and status totals
 * respecting the filtered and limited result set.
 *
 * @param {Object} options - Filtering and pagination options
 * @param {boolean} options.includeComponents - Whether to include component metadata
 * @param {number} options.limit - Maximum number of problems to return
 * @param {string[]} [options.tags] - Tags to filter problems
 * @param {string[]} [options.difficulties] - Difficulties to filter problems
 * @returns {Promise<Object>} - Object containing problems and metadata
 */
async function listProblems({ includeComponents, limit, tags, difficulties }) {
  // Build base query filters
  const where = {};

  if (tags && tags.length > 0) {
    where.tags = { $overlap: tags };
  }

  if (difficulties && difficulties.length > 0) {
    where.difficulty = { $in: difficulties };
  }

  // Fetch problems with filters and limit
  const problems = await Problem.findAll({
    where,
    limit,
    order: [['id', 'ASC']]
  });

  // Prepare metadata
  const metadata = {};

  if (includeComponents) {
    // Compute language totals and status totals for the filtered and limited problems
    const componentLanguageTotals = {};
    const componentStatusTotals = {};

    problems.forEach(problem => {
      if (problem.components && Array.isArray(problem.components)) {
        problem.components.forEach(component => {
          // Count languages
          if (component.language) {
            componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
          }
          // Count statuses
          if (component.status) {
            componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
          }
        });
      }
    });

    metadata.componentLanguageTotals = componentLanguageTotals;
    metadata.componentStatusTotals = componentStatusTotals;
  }

  return { problems, metadata };
}

module.exports = {
  listProblems
};
